solution.code:
#include <stdio.h>

int gcd(int a, int b) { return b == 0 ? a : gcd(b, a % b); }

#define LCM(a, b) ((a && b) ? ((a / gcd(a, b)) * b) : 0)

int main() {
    printf("%d\n", LCM(12, 18));
    return 0;
}
